 57→func setupHomeRoute(i InfoType, r *http.Request) InfoType {
 58→	jobRepo := repository.GetJobRepository()
 59→	groupBy := model.AggregateCluster
 60→
 61→	// startJobCount := time.Now()
 62→	stats, err := jobRepo.JobCountGrouped(r.Context(), nil, &groupBy)
 63→	if err != nil {
 64→		cclog.Warnf("failed to count jobs: %s", err.Error())
 65→	}
 66→	// cclog.Infof("Timer HOME ROUTE startJobCount: %s", time.Since(startJobCount))
 67→
 68→	// startRunningJobCount := time.Now()
 69→	stats, err = jobRepo.AddJobCountGrouped(r.Context(), nil, &groupBy, stats, "running")
 70→	if err != nil {
 71→		cclog.Warnf("failed to count running jobs: %s", err.Error())
 72→	}
 73→	// cclog.Infof("Timer HOME ROUTE startRunningJobCount: %s", time.Since(startRunningJobCount))
 74→
 75→	i["clusters"] = stats
 76→
 77→	if util.CheckFileExists("./var/notice.txt") {
