472→func SetupRoutes(router chi.Router, buildInfo web.Build) {
473→	userCfgRepo := repository.GetUserCfgRepo()
474→	for _, route := range routes {
475→		router.HandleFunc(route.Route, func(rw http.ResponseWriter, r *http.Request) {
476→			conf, err := userCfgRepo.GetUIConfig(repository.GetUserFromContext(r.Context()))
477→			if err != nil {
478→				http.Error(rw, err.Error(), http.StatusInternalServerError)
479→				return
480→			}
481→
482→			title := route.Title
483→			infos := route.Setup(map[string]any{}, r)
484→			if id, ok := infos["id"]; ok {
485→				title = strings.Replace(route.Title, "<ID>", id.(string), 1)
486→				if sid, ok := infos["sid"]; ok { // 2nd ID element
487→					title = strings.Replace(title, "<SID>", sid.(string), 1)
488→				}
489→			}
490→
491→			// Get User -> What if NIL?
492→			user := repository.GetUserFromContext(r.Context())
493→
494→			// Get Roles
495→			availableRoles, _ := schema.GetValidRolesMap(user)
496→
497→			resampling := resamplingForUser(conf)
498→
499→			page := web.Page{
500→				Title:      title,
501→				User:       *user,
502→				Roles:      availableRoles,
503→				Build:      buildInfo,
504→				Config:     conf,
505→				Resampling: resampling,
506→				Infos:      infos,
507→			}
508→
509→			if route.Filter {
510→				page.FilterPresets = buildFilterPresets(r.URL.Query())
511→			}
512→
513→			web.RenderTemplate(rw, route.Template, &page)
514→		})
515→	}
516→}
