518→func HandleSearchBar(rw http.ResponseWriter, r *http.Request, buildInfo web.Build) {
519→	user := repository.GetUserFromContext(r.Context())
520→	availableRoles, _ := schema.GetValidRolesMap(user)
521→
522→	if search := r.URL.Query().Get("searchId"); search != "" {
523→		repo := repository.GetJobRepository()
524→		splitSearch := strings.Split(search, ":")
525→
526→		if len(splitSearch) == 2 {
527→			switch strings.Trim(splitSearch[0], " ") {
528→			case "jobId":
529→				http.Redirect(rw, r, "/monitoring/jobs/?jobId="+url.QueryEscape(strings.Trim(splitSearch[1], " ")), http.StatusFound) // All Users: Redirect to Tablequery
530→			case "jobName":
531→				// Add Last 30 Days to migitate timeouts
532→				untilTime := strconv.FormatInt(time.Now().Unix(), 10)
533→				fromTime := strconv.FormatInt((time.Now().Unix() - int64(30*24*3600)), 10)
534→
535→				http.Redirect(rw, r, "/monitoring/jobs/?startTime="+fromTime+"-"+untilTime+"&jobName="+url.QueryEscape(strings.Trim(splitSearch[1], " ")), http.StatusFound) // All Users: Redirect to Tablequery
536→			case "projectId":
537→				http.Redirect(rw, r, "/monitoring/jobs/?projectMatch=eq&project="+url.QueryEscape(strings.Trim(splitSearch[1], " ")), http.StatusFound) // All Users: Redirect to Tablequery
538→			case "arrayJobId":
539→				// Add Last 30 Days to migitate timeouts
540→				untilTime := strconv.FormatInt(time.Now().Unix(), 10)
541→				fromTime := strconv.FormatInt((time.Now().Unix() - int64(30*24*3600)), 10)
542→
543→				http.Redirect(rw, r, "/monitoring/jobs/?startTime="+fromTime+"-"+untilTime+"&arrayJobId="+url.QueryEscape(strings.Trim(splitSearch[1], " ")), http.StatusFound) // All Users: Redirect to Tablequery
544→			case "username":
545→				if user.HasAnyRole([]schema.Role{schema.RoleAdmin, schema.RoleSupport, schema.RoleManager}) {
546→					http.Redirect(rw, r, "/monitoring/users/?user="+url.QueryEscape(strings.Trim(splitSearch[1], " "))+"&startTime=last30d", http.StatusFound)
547→				} else {
548→					web.RenderTemplate(rw, "message.tmpl", &web.Page{Title: "Error", MsgType: "alert-danger", Message: "Missing Access Rights", User: *user, Roles: availableRoles, Build: buildInfo})
549→				}
550→			case "name":
551→				usernames, _ := repo.FindColumnValues(user, strings.Trim(splitSearch[1], " "), "user", "username", "name")
552→				if len(usernames) != 0 {
553→					joinedNames := strings.Join(usernames, "&user=")
554→					http.Redirect(rw, r, "/monitoring/users/?user="+joinedNames+"&startTime=last30d", http.StatusFound)
555→				} else {
556→					if user.HasAnyRole([]schema.Role{schema.RoleAdmin, schema.RoleSupport, schema.RoleManager}) {
557→						http.Redirect(rw, r, "/monitoring/users/?user=NoUserNameFound&startTime=last30d", http.StatusPermanentRedirect)
558→					} else {
559→						web.RenderTemplate(rw, "message.tmpl", &web.Page{Title: "Error", MsgType: "alert-danger", Message: "Missing Access Rights", User: *user, Roles: availableRoles, Build: buildInfo})
560→					}
561→				}
562→			default:
563→				web.RenderTemplate(rw, "message.tmpl", &web.Page{Title: "Warning", MsgType: "alert-warning", Message: fmt.Sprintf("Unknown search type: %s", strings.Trim(splitSearch[0], " ")), User: *user, Roles: availableRoles, Build: buildInfo})
564→			}
565→		} else if len(splitSearch) == 1 {
566→
567→			jobid, username, project, jobname := repo.FindUserOrProjectOrJobname(user, strings.Trim(search, " "))
568→
569→			if jobid != "" {
570→				http.Redirect(rw, r, "/monitoring/jobs/?jobId="+url.QueryEscape(jobid), http.StatusFound) // JobId (Match)
571→			} else if username != "" {
572→				http.Redirect(rw, r, "/monitoring/user/"+username, http.StatusFound) // User: Redirect to user page of first match
573→			} else if project != "" {
574→				http.Redirect(rw, r, "/monitoring/jobs/?projectMatch=eq&project="+url.QueryEscape(project), http.StatusFound) // projectId (equal)
575→			} else if jobname != "" {
576→				// Add Last 30 Days to migitate timeouts
577→				untilTime := strconv.FormatInt(time.Now().Unix(), 10)
578→				fromTime := strconv.FormatInt((time.Now().Unix() - int64(30*24*3600)), 10)
579→
580→				http.Redirect(rw, r, "/monitoring/jobs/?startTime="+fromTime+"-"+untilTime+"&jobName="+url.QueryEscape(jobname), http.StatusFound) // 30D Fitler + JobName (contains)
581→			} else {
582→				web.RenderTemplate(rw, "message.tmpl", &web.Page{Title: "Info", MsgType: "alert-info", Message: "Search without result", User: *user, Roles: availableRoles, Build: buildInfo})
583→			}
584→
585→		} else {
586→			web.RenderTemplate(rw, "message.tmpl", &web.Page{Title: "Error", MsgType: "alert-danger", Message: "Searchbar query parameters malformed", User: *user, Roles: availableRoles, Build: buildInfo})
587→		}
588→	} else {
589→		web.RenderTemplate(rw, "message.tmpl", &web.Page{Title: "Warning", MsgType: "alert-warning", Message: "Empty search", User: *user, Roles: availableRoles, Build: buildInfo})
590→	}
591→}
